import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { 
  Home, 
  FileText, 
  CreditCard, 
  History, 
  BarChart3, 
  Settings, 
  LogOut,
  DollarSign,
  TrendingUp,
  RefreshCw,
  Users,
  Bell,
  Target,
  AlertTriangle
} from 'lucide-react';

const Sidebar = ({ userRole, currentScreen, onNavigate, onLogout, onShowRoadmap, setUserRole }) => {
  const navigate = useNavigate();
  const location = useLocation();

  console.log('Sidebar props:', { userRole, setUserRole: typeof setUserRole });

  const studentMenuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: Home, path: '/dashboard' },
    { id: 'debt-details', label: 'Tra cứu công nợ', icon: FileText, path: '/debt-details' },
    { id: 'payment', label: 'Thanh toán', icon: CreditCard, path: '/qr-payment' },
    { id: 'payment-history', label: 'Lịch sử thanh toán', icon: History, path: '/payment-history' },
  ];

  const accountantMenuItems = [
    { id: 'dashboard', label: 'Dashboard Báo cáo', icon: BarChart3, path: '/dashboard' },
    { id: 'traceability-matrix', label: 'Ma trận Dấu vết', icon: Target, path: '/traceability-matrix' },
    { id: 'reminder-settings', label: 'Cài đặt Nhắc nợ', icon: Bell, path: '/reminder-settings' },
  ];

  const commonMenuItems = [
    { id: 'financial-support', label: 'Hỗ trợ tài chính & Vay vốn', icon: DollarSign, action: 'roadmap' },
    { id: 'fee-waiver', label: 'Hoàn phí & Miễn giảm', icon: AlertTriangle, action: 'roadmap' },
  ];

  const menuItems = userRole === 'STUDENT' ? studentMenuItems : accountantMenuItems;

  const handleMenuItemClick = (item) => {
    if (item.action === 'roadmap') {
      onShowRoadmap();
    } else if (item.path) {
      onNavigate(item.id);
      navigate(item.path);
    }
  };

  const isActive = (itemId) => {
    if (itemId === 'dashboard' && location.pathname === '/') {
      return true;
    }
    return currentScreen === itemId || location.pathname.includes(itemId);
  };

  return (
    <aside className="w-64 bg-white shadow-lg border-r border-teal-100">
      <div className="p-6 border-b border-teal-100">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-12 h-12 logo-hce flex items-center justify-center">
              <span className="text-xl">HCE</span>
            </div>
            <div>
              <h2 className="font-bold text-teal-900 text-lg">FMS</h2>
              <p className="text-xs text-teal-600">
                {userRole === 'STUDENT' ? 'Sinh viên' : 'Kế toán / Admin'}
              </p>
            </div>
          </div>

          {/* Role Switch Button */}
          <button
            onClick={() => {
              console.log('Switch role clicked, setUserRole type:', typeof setUserRole);
              if (typeof setUserRole === 'function') {
                setUserRole(userRole === 'STUDENT' ? 'ACCOUNTANT' : 'STUDENT');
              } else {
                console.error('setUserRole is not a function!');
              }
            }}
            className="flex items-center gap-2 px-3 py-2 bg-green-600 text-white text-sm rounded-lg hover:bg-green-700 shadow-lg"
          >
            <RefreshCw className="w-4 h-4" />
            Switch Role
          </button>
        </div>
      </div>

      <nav className="flex-1 p-4">
        <ul className="space-y-1">
          {menuItems.map((item) => (
            <li key={item.id}>
              <button
                onClick={() => handleMenuItemClick(item)}
                className={`sidebar-item w-full text-left ${isActive(item.id) ? 'active' : ''}`}
              >
                <item.icon className="w-5 h-5 mr-3 text-green-400" />
                <span>{item.label}</span>
              </button>
            </li>
          ))}

          <li className="pt-4 mt-4 border-t border-green-700">
            {commonMenuItems.map((item) => (
              <button
                key={item.id}
                onClick={() => handleMenuItemClick(item)}
                className={`sidebar-item w-full text-left ${isActive(item.id) ? 'active' : ''}`}
              >
                <item.icon className="w-5 h-5 mr-3 text-green-400" />
                <span>{item.label}</span>
              </button>
            ))}
          </li>
        </ul>
      </nav>

      <div className="p-4 border-t border-gray-200">
        <button
          onClick={onLogout}
          className="sidebar-item w-full text-left text-red-600 hover:bg-red-50"
        >
          <LogOut className="w-5 h-5 mr-3" />
          <span>Đăng xuất</span>
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;
